import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as a,e as i}from"./app-0cb71135.js";const l={},n=i('<h1 id="《深入理解-sentinel》笔记" tabindex="-1"><a class="header-anchor" href="#《深入理解-sentinel》笔记" aria-hidden="true">#</a> 《深入理解 Sentinel》笔记</h1><h2 id="开篇词-一次服务雪崩问题排查经历" tabindex="-1"><a class="header-anchor" href="#开篇词-一次服务雪崩问题排查经历" aria-hidden="true">#</a> 开篇词：一次服务雪崩问题排查经历</h2><blockquote><p><strong>什么是服务雪崩</strong></p></blockquote><p><strong>服务雪崩</strong>是指：在微服务项目中指由于突发流量导致某个服务不可用，从而导致上游服务不可用，并产生级联效应，最终导致整个系统不可用。</p><p>当一切正常时，整体系统如下所示：</p><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/snap/202401280931974.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>在分布式系统架构下，这些强依赖的子服务稳定与否对系统的影响非常大。但是，依赖的子服务可能有很多不可控问题：如网络连接、资源繁忙、服务宕机等。例如：下图中有一个 QPS 为 50 的依赖服务 I 出现不可用，但是其他依赖服务是可用的。</p><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/snap/202401280931939.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>当流量很大的情况下，某个依赖的阻塞，会导致上游服务请求被阻塞。当这种级联故障愈演愈烈，就可能造成整个线上服务不可用的雪崩效应，如下图。这种情况若持续恶化，如果上游服务本身还被其他服务所依赖，就可能出现多米洛骨牌效应，导致多个服务都无法正常工作。</p><figure><img src="https://github.com/Netflix/Hystrix/wiki/images/soa-3-640.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="为什么需要服务降级以及常见的几种降级方式" tabindex="-1"><a class="header-anchor" href="#为什么需要服务降级以及常见的几种降级方式" aria-hidden="true">#</a> 为什么需要服务降级以及常见的几种降级方式</h2><p>服务降级是为了保障服务能够稳定运行的一种保护方式，应对流量突增用降级牺牲一些流量换取系统的稳定。常见的服务降级实现方式有：开关降级、限流降级、熔断降级。</p><p>限流降级与熔断降级都可以实现在消费端限流或者服务端限流，限流可以根据流量控制策略处理超过阈值的流量。</p><ul><li>限流即便没有达到系统的瓶颈，只要流量达到设定的阈值，就会触发限流；</li><li>熔断尽最大的可能去完成所有的请求，容忍一些失败，熔断也能自动恢复。熔断的常见降级策略： <ul><li>在每秒请求异常数超过多少时触发熔断降级</li><li>在每秒请求异常错误率超过多少时触发熔断降级</li><li>在每秒请求平均耗时超过多少时触发熔断降级</li></ul></li></ul><p>开关降级适用于促销活动这种可以明确预估到并发会突增的场景。</p><h2 id="为什么选择-sentinel-sentinel-与-hystrix-的对比" tabindex="-1"><a class="header-anchor" href="#为什么选择-sentinel-sentinel-与-hystrix-的对比" aria-hidden="true">#</a> 为什么选择 Sentinel，Sentinel 与 Hystrix 的对比</h2><table><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">Sentinel</th><th style="text-align:left;">Hystrix</th></tr></thead><tbody><tr><td style="text-align:left;">社区活跃度</td><td style="text-align:left;">Github 13K star</td><td style="text-align:left;">官方停止维护</td></tr><tr><td style="text-align:left;">隔离策略</td><td style="text-align:left;">信号量隔离</td><td style="text-align:left;">线程池隔离/信号量隔离</td></tr><tr><td style="text-align:left;">熔断降级策略</td><td style="text-align:left;">基于响应时间或失败比率</td><td style="text-align:left;">基于失败比率</td></tr><tr><td style="text-align:left;">实时指标实现</td><td style="text-align:left;">滑动窗口</td><td style="text-align:left;">滑动窗口（基于 RxJava）</td></tr><tr><td style="text-align:left;">规则配置</td><td style="text-align:left;">支持多种数据源</td><td style="text-align:left;">支持多种数据源</td></tr><tr><td style="text-align:left;">扩展性</td><td style="text-align:left;">多个 SPI 扩展点</td><td style="text-align:left;">插件的形式</td></tr><tr><td style="text-align:left;">基于注解的支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td></tr><tr><td style="text-align:left;">限流</td><td style="text-align:left;">基于 QPS，支持基于调用关系的限流</td><td style="text-align:left;">有限的支持</td></tr><tr><td style="text-align:left;">流量整形</td><td style="text-align:left;">支持慢启动、匀速器模式</td><td style="text-align:left;">不支持</td></tr><tr><td style="text-align:left;">系统负载保护</td><td style="text-align:left;">支持</td><td style="text-align:left;">不支持</td></tr><tr><td style="text-align:left;">控制台</td><td style="text-align:left;">开箱即用，可配置规则、查看秒级监控、机器发现等</td><td style="text-align:left;">不完善</td></tr><tr><td style="text-align:left;">常见框架的适配</td><td style="text-align:left;">Servlet、Spring Cloud、Dubbo、gRPC 等</td><td style="text-align:left;">Servlet、Spring Cloud Netflix</td></tr></tbody></table><h2 id="sentinel-基于滑动窗口的实时指标数据统计" tabindex="-1"><a class="header-anchor" href="#sentinel-基于滑动窗口的实时指标数据统计" aria-hidden="true">#</a> Sentinel 基于滑动窗口的实时指标数据统计</h2><ul><li>WindowWrap 用于包装 Bucket，随着 Bucket 一起创建。</li><li>WindowWrap 数组实现滑动窗口，Bucket 只负责统计各项指标数据，WindowWrap 用于记录 Bucket 的时间窗口信息。</li><li>定位 Bucket 实际上是定位 WindowWrap，拿到 WindowWrap 就能拿到 Bucket。</li></ul><h2 id="sentinel-的一些概念与核心类介绍" tabindex="-1"><a class="header-anchor" href="#sentinel-的一些概念与核心类介绍" aria-hidden="true">#</a> Sentinel 的一些概念与核心类介绍</h2><ul><li>资源：资源是 Sentinel 的关键概念。资源，可以是一个方法、一段代码、由应用提供的接口，或者由应用调用其它应用的接口。</li><li>规则：围绕资源的实时状态设定的规则，包括流量控制规则、熔断降级规则以及系统保护规则、自定义规则。</li><li>降级：在流量剧增的情况下，为保证系统能够正常运行，根据资源的实时状态、访问流量以及系统负载有策略的拒绝掉一部分流量。</li></ul><h2 id="sentinel-中的责任链模式与-sentinel-的整体工作流程" tabindex="-1"><a class="header-anchor" href="#sentinel-中的责任链模式与-sentinel-的整体工作流程" aria-hidden="true">#</a> Sentinel 中的责任链模式与 Sentinel 的整体工作流程</h2><h2 id="_07-java-spi-及-spi-在-sentinel-中的应用" tabindex="-1"><a class="header-anchor" href="#_07-java-spi-及-spi-在-sentinel-中的应用" aria-hidden="true">#</a> 07 Java SPI 及 SPI 在 Sentinel 中的应用</h2><h2 id="_08-资源指标数据统计的实现全解析-上" tabindex="-1"><a class="header-anchor" href="#_08-资源指标数据统计的实现全解析-上" aria-hidden="true">#</a> 08 资源指标数据统计的实现全解析（上）</h2><h2 id="_09-资源指标数据统计的实现全解析-下" tabindex="-1"><a class="header-anchor" href="#_09-资源指标数据统计的实现全解析-下" aria-hidden="true">#</a> 09 资源指标数据统计的实现全解析（下）</h2><h2 id="_10-限流降级与流量效果控制器-上" tabindex="-1"><a class="header-anchor" href="#_10-限流降级与流量效果控制器-上" aria-hidden="true">#</a> 10 限流降级与流量效果控制器（上）</h2><h2 id="_11-限流降级与流量效果控制器-中" tabindex="-1"><a class="header-anchor" href="#_11-限流降级与流量效果控制器-中" aria-hidden="true">#</a> 11 限流降级与流量效果控制器（中）</h2><h2 id="_12-限流降级与流量效果控制器-下" tabindex="-1"><a class="header-anchor" href="#_12-限流降级与流量效果控制器-下" aria-hidden="true">#</a> 12 限流降级与流量效果控制器（下）</h2><h2 id="_13-熔断降级与系统自适应限流" tabindex="-1"><a class="header-anchor" href="#_13-熔断降级与系统自适应限流" aria-hidden="true">#</a> 13 熔断降级与系统自适应限流</h2><h2 id="_14-黑白名单限流与热点参数限流" tabindex="-1"><a class="header-anchor" href="#_14-黑白名单限流与热点参数限流" aria-hidden="true">#</a> 14 黑白名单限流与热点参数限流</h2><h2 id="_15-自定义-processorslot-实现开关降级" tabindex="-1"><a class="header-anchor" href="#_15-自定义-processorslot-实现开关降级" aria-hidden="true">#</a> 15 自定义 ProcessorSlot 实现开关降级</h2><h2 id="_16-sentinel-动态数据源-规则动态配置" tabindex="-1"><a class="header-anchor" href="#_16-sentinel-动态数据源-规则动态配置" aria-hidden="true">#</a> 16 Sentinel 动态数据源：规则动态配置</h2><h2 id="_17-sentinel-主流框架适配" tabindex="-1"><a class="header-anchor" href="#_17-sentinel-主流框架适配" aria-hidden="true">#</a> 17 Sentinel 主流框架适配</h2><h2 id="_18-sentinel-集群限流的实现-上" tabindex="-1"><a class="header-anchor" href="#_18-sentinel-集群限流的实现-上" aria-hidden="true">#</a> 18 Sentinel 集群限流的实现（上）</h2><h2 id="_19-sentinel-集群限流的实现-下" tabindex="-1"><a class="header-anchor" href="#_19-sentinel-集群限流的实现-下" aria-hidden="true">#</a> 19 Sentinel 集群限流的实现（下）</h2><h2 id="_20-结束语-sentinel-对应用的性能影响如何" tabindex="-1"><a class="header-anchor" href="#_20-结束语-sentinel-对应用的性能影响如何" aria-hidden="true">#</a> 20 结束语：Sentinel 对应用的性能影响如何？</h2><h2 id="_21-番外篇-sentinel-1-8-0-熔断降级新特性解读" tabindex="-1"><a class="header-anchor" href="#_21-番外篇-sentinel-1-8-0-熔断降级新特性解读" aria-hidden="true">#</a> 21 番外篇：Sentinel 1.8.0 熔断降级新特性解读</h2>',37),d=[n];function r(s,h){return e(),a("div",null,d)}const o=t(l,[["render",r],["__file","index.html.vue"]]);export{o as default};
